{
  "summary": "Esta ronda de diseño se enfoca en empoderar al usuario con control sobre la comparación de documentos, mejorar la fluidez y el feedback de la interfaz a través de microinteracciones, y transformar hallazgos clave de Helios en alertas proactivas y priorizadas. El objetivo es hacer la auditoría más intuitiva, eficiente y humana, manteniendo la promesa de Helios como un asistente inteligente y no un reemplazo de la revisión experta.",
  "ui_priorities": [
    "Facilitar la selección manual de documentos para comparación de forma intuitiva y mobile-first.",
    "Añadir capas de feedback visual y táctil con microinteracciones sutiles para una experiencia más fluida y agradable.",
    "Consolidar y priorizar hallazgos recurrentes o de alta relevancia de Helios en un formato de alerta claro y accionable.",
    "Mantener la interfaz limpia, minimalista y fácil de entender, evitando la sobrecarga de información.",
    "Incentivar la carga de más documentos para maximizar el valor de Helios y la funcionalidad de la app."
  ],
  "manual_compare": {
    "interaction_model": "Selección directa de dos documentos desde la lista principal del expediente. El usuario toca un documento para seleccionarlo como 'primero', luego toca otro para seleccionarlo como 'segundo'. Un botón de acción flotante se activa al tener dos seleccionados.",
    "default_behavior": "Si no hay documentos seleccionados manualmente, el bloque de Helios mantiene su funcionalidad de comparación automática (ej. 'Helios: ¿Qué cambió aquí?'). Si solo se selecciona un documento, se muestra un mensaje claro invitando a seleccionar el segundo.",
    "mobile_pattern": "En la vista de lista de documentos, cada ítem tendrá un área táctil para la selección. Al tocar, el documento adquiere un estado visual de 'seleccionado (1/2)'. Al tocar un segundo, este adquiere el estado 'seleccionado (2/2)' y un botón flotante 'Comparar (2)' aparece en la parte inferior de la pantalla. Un toque adicional en un documento ya seleccionado lo deselecciona.",
    "fallback_when_few_docs": "Si hay menos de dos documentos en el expediente, el bloque de comparación manual mostrará un mensaje incentivando a subir más documentos. Ejemplo: 'Sube al menos dos documentos para que Helios pueda compararlos y revelarte sus diferencias clave. ¡Cada documento hace a Helios más inteligente!'",
    "recommended_controls": [
      "Estado visual de 'seleccionado' en el ítem de la lista de documentos (borde, color de fondo sutil).",
      "Indicador numérico (1/2, 2/2) o icono de 'check' en los documentos seleccionados.",
      "Botón de acción flotante ('FAB') 'Comparar (2)' que aparece solo cuando hay dos documentos seleccionados.",
      "Opción de 'Cancelar selección' o 'Limpiar' en el FAB o en un encabezado contextual."
    ]
  },
  "microinteractions": [
    {
      "target": "Selección de documento para comparar",
      "effect": "Un ligero 'pop' o escala del ítem de la lista al ser tocado, acompañado de un cambio sutil de color de fondo o un borde animado que confirma la selección.",
      "rationale": "Proporciona feedback táctil y visual inmediato, confirmando al usuario que su acción fue registrada y mejorando la sensación de control."
    },
    {
      "target": "Carga de resultados de comparación de Helios",
      "effect": "Una transición suave de los elementos del contenido (ej. 'skeleton loader' que se llena gradualmente, o un fade-in escalonado de los hallazgos) en lugar de una carga abrupta.",
      "rationale": "Reduce la percepción de espera, hace la interfaz más responsiva y mantiene la elegancia visual durante el procesamiento de Helios."
    },
    {
      "target": "Navegación en la línea de tiempo del expediente",
      "effect": "Desplazamiento suave y elástico entre los hitos o eventos de la línea de tiempo, con un ligero 'snap' al centrar un elemento.",
      "rationale": "Mejora la fluidez de la exploración histórica del expediente, haciendo la interacción más placentera y menos robótica."
    },
    {
      "target": "Aparición de nueva alerta priorizada",
      "effect": "La tarjeta de alerta se desliza suavemente desde la parte superior o inferior de la sección de alertas, o un ligero 'pulse' inicial al aparecer.",
      "rationale": "Asegura que el usuario note la nueva información importante sin ser intrusivo, dirigiendo su atención de forma sutil."
    }
  ],
  "prioritized_alerts": {
    "logic": "Helios monitorea los hallazgos recurrentes en el expediente (ej. el mismo tipo de inconsistencia en múltiples documentos) y también identifica hallazgos de alta relevancia definidos por reglas de negocio (ej. cambios en razón social, fechas críticas faltantes). Estos se consolidan y se presentan como 'Alertas Priorizadas', mostrando el contexto (dónde se encontró) y el momento (cuándo se detectó).",
    "cards": [
      {
        "title": "Inconsistencia recurrente en fechas de alta",
        "when": "Detectado en 3 documentos",
        "body": "Helios ha notado que las fechas de alta de empleados o contratos no coinciden en los documentos 'Contrato X', 'Nómina Y' y 'IMSS Z'. Esto podría indicar un error o una discrepancia importante que requiere tu atención.",
        "priority": "high",
        "timestamp_pattern": "Hace 2 semanas"
      },
      {
        "title": "Documento clave pendiente: Acta Constitutiva",
        "when": "Sugerido por Helios",
        "body": "Basado en el tipo de expediente y los documentos existentes, Helios sugiere que el Acta Constitutiva podría ser un documento clave faltante para una revisión más completa y robusta.",
        "priority": "medium",
        "timestamp_pattern": "Hoy"
      },
      {
        "title": "Cambio en razón social detectado",
        "when": "En la última carga de documentos",
        "body": "Helios identificó un cambio en la razón social de 'Empresa A S.A. de C.V.' a 'Empresa B S.A.S.' entre los documentos 'Acta 2020' y 'Acta 2022'. Confirma si este cambio es correcto y está debidamente documentado.",
        "priority": "high",
        "timestamp_pattern": "Hace 3 días"
      }
    ]
  },
  "copy_examples": {
    "compare_cta": "Comparar seleccionados (2)",
    "alert_heading": "Alertas importantes de Helios",
    "alert_body": "Helios ha identificado un patrón recurrente: las fechas de inicio de contrato varían en múltiples documentos. Revisa 'Contrato A' y 'Nómina B' para más detalles.",
    "empty_state": "¡Tu expediente está creciendo! Sube más documentos para que Helios pueda encontrar más conexiones y ayudarte a auditar mejor. Con al menos dos, podrás compararlos manualmente."
  },
  "implementation_order": [
    "Desarrollo de la UI para la selección manual de documentos (estados, controles, FAB).",
    "Integración del frontend con el endpoint de Helios para la comparación manual de dos documentos.",
    "Implementación de microinteracciones básicas para la selección y carga de comparación.",
    "Diseño y desarrollo de la sección de 'Alertas Priorizadas' (estructura de tarjetas, visualización).",
    "Integración del frontend con el backend para la ingesta y visualización de alertas generadas por Helios.",
    "Refinamiento de microinteracciones y ajuste de copys para asegurar el tono y la claridad."
  ],
  "risks_to_avoid": [
    "Sobrecargar la interfaz con demasiadas opciones de selección o estados confusos, especialmente en móvil.",
    "Generar alertas falsas positivas o irrelevantes que erosionen la confianza del usuario en Helios.",
    "Prometer conclusiones definitivas o 'resoluciones' de casos, manteniendo a Helios como una guía útil, no un reemplazo de la revisión humana.",
    "Introducir microinteracciones que distraigan o ralenticen la experiencia en lugar de mejorarla.",
    "Crear un flujo de comparación manual más complejo o menos eficiente que la comparación automática ya existente."
  ]
}
